    /// Returns the project's `.forge` directory path.
    fn forge_dir() -> PathBuf {
        PathBuf::from(env!("CARGO_MANIFEST_DIR")).join(".forge")
    }

    /// Returns a `PromptLoader` pointing at the real `.forge` directory.
    fn loader() -> PromptLoader {
