   1→//! Review dispatcher for invoking review specialists after phase completion.
   2→//!
   3→//! The dispatcher coordinates review specialist execution:
   4→//! - Spawns review specialists (optionally in parallel)
   5→//! - Collects findings into a ReviewAggregation
   6→//! - Handles gating reviews via the arbiter
   7→//!
   8→//! ## Usage
   9→//!
  10→//! ```no_run
  11→//! use forge::review::dispatcher::{ReviewDispatcher, DispatcherConfig, PhaseReviewConfig};
  12→//! use forge::review::{ReviewSpecialist, SpecialistType};
  13→//!
  14→//! # async fn example() -> anyhow::Result<()> {
  15→//! let config = DispatcherConfig::default();
  16→//! let dispatcher = ReviewDispatcher::new(config);
  17→//!
  18→//! let review_config = PhaseReviewConfig::new("05", "OAuth Integration")
  19→//!     .add_specialist(ReviewSpecialist::gating(SpecialistType::SecuritySentinel))
  20→//!     .add_specialist(ReviewSpecialist::advisory(SpecialistType::PerformanceOracle));
  21→//!
  22→//! let result = dispatcher.dispatch(review_config).await?;
  23→//!
  24→//! if result.requires_action() {
  25→//!     println!("Reviews found issues: {}", result.aggregation);
  26→//! }
  27→//! # Ok(())
  28→//! # }
  29→//! ```
  30→
  31→use crate::review::{
  32→    ArbiterConfig, ArbiterExecutor, ArbiterInput, ArbiterResult, FindingSeverity,
