 212→/// Result of a review dispatch operation.
 213→#[derive(Debug, Clone, Serialize, Deserialize)]
 214→pub struct DispatchResult {
 215→    /// Aggregated review results.
 216→    pub aggregation: ReviewAggregation,
 217→    /// Whether any gating review failed.
 218→    pub has_gating_failures: bool,
 219→    /// Arbiter decision if gating reviews failed.
 220→    #[serde(skip_serializing_if = "Option::is_none")]
 221→    pub arbiter_result: Option<ArbiterResult>,
 222→    /// Total duration for all reviews.
 223→    pub duration: Duration,
 224→}
 225→
 226→impl DispatchResult {
 227→    /// Create a successful dispatch result (no gating failures).
 228→    pub fn success(aggregation: ReviewAggregation, duration: Duration) -> Self {
 229→        Self {
 230→            has_gating_failures: aggregation.has_gating_failures(),
 231→            aggregation,
 232→            arbiter_result: None,
 233→            duration,
 234→        }
 235→    }
 236→
 237→    /// Create a dispatch result with arbiter decision.
 238→    pub fn with_arbiter(
 239→        aggregation: ReviewAggregation,
 240→        arbiter_result: ArbiterResult,
 241→        duration: Duration,
 242→    ) -> Self {
 243→        Self {
 244→            has_gating_failures: aggregation.has_gating_failures(),
 245→            aggregation,
 246→            arbiter_result: Some(arbiter_result),
 247→            duration,
 248→        }
 249→    }
 250→
 251→    /// Check if the dispatch requires action (failed gating reviews).
 252→    pub fn requires_action(&self) -> bool {
 253→        self.has_gating_failures
 254→    }
 255→
 256→    /// Check if we can proceed (either no failures, or arbiter said proceed).
 257→    pub fn can_proceed(&self) -> bool {
 258→        if !self.has_gating_failures {
 259→            return true;
 260→        }
 261→        self.arbiter_result
 262→            .as_ref()
 263→            .is_some_and(|r| r.decision.decision.allows_progression())
 264→    }
 265→
 266→    /// Check if we need to fix and retry.
 267→    pub fn needs_fix(&self) -> bool {
 268→        self.arbiter_result
 269→            .as_ref()
 270→            .is_some_and(|r| r.decision.decision.requires_fix())
 271→    }
 272→
 273→    /// Check if the phase has terminally failed.
 274→    pub fn is_phase_failed(&self) -> bool {
 275→        self.has_gating_failures
 276→            && self
 277→                .arbiter_result
 278→                .as_ref()
 279→                .is_none_or(|r| r.decision.decision.fails_phase())
 280→    }
 281→
 282→    /// Get the fix instructions if the verdict is Fix.
 283→    pub fn fix_instructions(&self) -> Option<&str> {
 284→        self.arbiter_result
 285→            .as_ref()
 286→            .and_then(|r| r.decision.fix_instructions.as_deref())
 287→    }
 288→
 289→    /// Get the failure summary if the verdict is FailPhase.
 290→    pub fn failure_summary(&self) -> Option<&str> {
 291→        self.arbiter_result
 292→            .as_ref()
 293→            .and_then(|r| r.decision.failure_summary.as_deref())
 294→    }
 295→}
