 297→/// The review dispatcher coordinates review specialist execution.
 298→pub struct ReviewDispatcher {
 299→    config: DispatcherConfig,
 300→}
 301→
 302→impl ReviewDispatcher {
 303→    /// Create a new review dispatcher with the given configuration.
 304→    pub fn new(config: DispatcherConfig) -> Self {
 305→        Self { config }
 306→    }
 307→
 308→    /// Create a dispatcher with default configuration.
 309→    pub fn with_defaults() -> Self {
 310→        Self::new(DispatcherConfig::default())
 311→    }
 312→
 313→    /// Dispatch review specialists for a phase.
 314→    ///
 315→    /// This is the main entry point for review dispatch. It:
 316→    /// 1. Runs all configured review specialists
 317→    /// 2. Aggregates their findings
 318→    /// 3. Invokes the arbiter if there are gating failures
 319→    /// 4. Returns the dispatch result
 320→    pub async fn dispatch(&self, review_config: PhaseReviewConfig) -> Result<DispatchResult> {
 321→        let start = Instant::now();
 322→        info!(
 323→            specialists = review_config.specialists.len(),
 324→            phase = %review_config.phase,
 325→            "Review dispatch started"
 326→        );
 327→
 328→        if review_config.specialists.is_empty() {
 329→            // No specialists configured, return empty success
 330→            return Ok(DispatchResult::success(
 331→                ReviewAggregation::new(&review_config.phase),
 332→                start.elapsed(),
 333→            ));
 334→        }
 335→
 336→        if self.config.verbose {
 337→            debug!(
 338→                "Dispatching {} specialists for phase {}",
 339→                review_config.specialists.len(),
 340→                review_config.phase
 341→            );
 342→        }
 343→
 344→        // Run review specialists
 345→        let reports = if self.config.parallel {
 346→            self.run_parallel_reviews(&review_config).await?
 347→        } else {
 348→            self.run_sequential_reviews(&review_config).await?
 349→        };
 350→
 351→        // Build aggregation
 352→        let aggregation = ReviewAggregation::new(&review_config.phase)
 353→            .add_reports(reports)
 354→            .with_parallel_execution(self.config.parallel)
 355→            .with_total_duration_ms(start.elapsed().as_millis() as u64);
 356→
 357→        info!(
 358→            total_findings = aggregation.all_findings_count(),
 359→            reports = aggregation.reports_count(),
 360→            verdict = %aggregation.overall_verdict(),
 361→            "Review aggregation complete"
 362→        );
 363→
 364→        if self.config.verbose {
 365→            debug!(
 366→                "Aggregation complete: {} reports, {} findings, verdict: {}",
 367→                aggregation.reports_count(),
 368→                aggregation.all_findings_count(),
 369→                aggregation.overall_verdict()
 370→            );
 371→        }
 372→
 373→        // Handle gating failures via arbiter
 374→        if aggregation.has_gating_failures() && review_config.has_gating_specialists() {
 375→            let arbiter_result = self.invoke_arbiter(&aggregation, &review_config).await?;
 376→            Ok(DispatchResult::with_arbiter(
 377→                aggregation,
 378→                arbiter_result,
 379→                start.elapsed(),
 380→            ))
 381→        } else {
 382→            Ok(DispatchResult::success(aggregation, start.elapsed()))
 383→        }
 384→    }
 385→
 386→    /// Run review specialists in parallel.
 387→    async fn run_parallel_reviews(
 388→        &self,
 389→        review_config: &PhaseReviewConfig,
 390→    ) -> Result<Vec<ReviewReport>> {
 391→        use futures::future::join_all;
 392→
 393→        let futures: Vec<_> = review_config
 394→            .specialists
 395→            .iter()
 396→            .map(|specialist| self.run_single_review(specialist, review_config))
 397→            .collect();
 398→
 399→        let results = join_all(futures).await;
 400→
 401→        let mut reports = Vec::new();
 402→        for result in results {
 403→            match result {
 404→                Ok(report) => reports.push(report),
 405→                Err(e) => {
 406→                    warn!("Specialist failed: {}", e);
 407→                    // Continue with other reviews
 408→                }
 409→            }
 410→        }
 411→
 412→        Ok(reports)
 413→    }
 414→
 415→    /// Run review specialists sequentially.
 416→    async fn run_sequential_reviews(
 417→        &self,
 418→        review_config: &PhaseReviewConfig,
 419→    ) -> Result<Vec<ReviewReport>> {
 420→        let mut reports = Vec::new();
 421→
 422→        for specialist in &review_config.specialists {
 423→            match self.run_single_review(specialist, review_config).await {
 424→                Ok(report) => reports.push(report),
 425→                Err(e) => {
 426→                    warn!("Specialist {} failed: {}", specialist.display_name(), e);
 427→                    // Continue with other reviews
 428→                }
 429→            }
 430→        }
 431→
 432→        Ok(reports)
 433→    }
