 435→    /// Run a single review specialist.
 436→    async fn run_single_review(
 437→        &self,
 438→        specialist: &ReviewSpecialist,
 439→        review_config: &PhaseReviewConfig,
 440→    ) -> Result<ReviewReport> {
 441→        let start = Instant::now();
 442→
 443→        if self.config.verbose {
 444→            debug!(
 445→                "Starting {} for phase {}",
 446→                specialist.display_name(),
 447→                review_config.phase
 448→            );
 449→        }
 450→
 451→        // Build the review prompt
 452→        let prompt = build_review_prompt(specialist, review_config);
 453→
 454→        // Run Claude with the review prompt
 455→        let output = self.run_claude_review(&prompt).await?;
 456→
 457→        // Parse the review output
 458→        let report = parse_review_output(
 459→            &output,
 460→            &review_config.phase,
 461→            &specialist.agent_name(),
 462→            specialist.is_gating(),
 463→        )
 464→        .with_duration_ms(start.elapsed().as_millis() as u64);
 465→
 466→        if self.config.verbose {
 467→            debug!(
 468→                "{} completed: {} ({} findings)",
 469→                specialist.display_name(),
 470→                report.verdict,
 471→                report.findings_count()
 472→            );
 473→        }
 474→
 475→        Ok(report)
 476→    }
 477→
 478→    /// Run Claude to perform a review.
 479→    async fn run_claude_review(&self, prompt: &str) -> Result<String> {
 480→        let mut cmd = Command::new(&self.config.claude_cmd);
 481→        cmd.arg("--print");
 482→
 483→        if self.config.skip_permissions {
 484→            cmd.arg("--dangerously-skip-permissions");
 485→        }
 486→
 487→        // Reviews are read-only — restrict to safe tools
 488→        cmd.arg("--allowed-tools")
 489→            .arg("Read,Glob,Grep,WebSearch,WebFetch");
 490→
 491→        if let Some(ref working_dir) = self.config.working_dir {
 492→            cmd.current_dir(working_dir);
 493→        }
 494→
 495→        cmd.stdin(Stdio::piped())
 496→            .stdout(Stdio::piped())
 497→            .stderr(Stdio::inherit());
 498→
 499→        let mut child = cmd.spawn().context("Failed to spawn Claude process")?;
 500→
 501→        // Write prompt to stdin
 502→        if let Some(mut stdin) = child.stdin.take() {
 503→            stdin
 504→                .write_all(prompt.as_bytes())
 505→                .await
 506→                .context("Failed to write prompt to stdin")?;
 507→            stdin.shutdown().await.context("Failed to close stdin")?;
 508→        }
 509→
 510→        // Read stdout
 511→        let stdout = child.stdout.take().context("Failed to get stdout")?;
 512→        let reader = BufReader::new(stdout);
 513→        let mut lines = reader.lines();
 514→        let mut output = String::new();
 515→
 516→        while let Ok(Some(line)) = lines.next_line().await {
 517→            output.push_str(&line);
 518→            output.push('\n');
 519→        }
 520→
 521→        // Wait for process with timeout
 522→        let status = tokio::time::timeout(self.config.review_timeout, child.wait())
 523→            .await
 524→            .context("Review timed out")?
 525→            .context("Failed to wait for process")?;
 526→
 527→        if !status.success() {
 528→            anyhow::bail!(
 529→                "Claude review process exited with code {}",
 530→                status.code().unwrap_or(-1)
 531→            );
 532→        }
 533→
 534→        Ok(output)
 535→    }
