 537→    /// Invoke the arbiter to handle gating failures.
 538→    async fn invoke_arbiter(
 539→        &self,
 540→        aggregation: &ReviewAggregation,
 541→        review_config: &PhaseReviewConfig,
 542→    ) -> Result<ArbiterResult> {
 543→        if self.config.verbose {
 544→            debug!(
 545→                "Invoking arbiter for {} gating failure(s)",
 546→                aggregation.gating_failures().len()
 547→            );
 548→        }
 549→
 550→        let executor = ArbiterExecutor::new(self.config.arbiter.clone());
 551→
 552→        let input = ArbiterInput::from_aggregation(
 553→            aggregation,
 554→            review_config.budget,
 555→            review_config.iterations_used,
 556→        )
 557→        .with_phase_name(&review_config.phase_name);
 558→
 559→        executor.decide_with_quick_check(input).await
 560→    }
 561→}
