  1→//! Review specialist types for quality gating.
  2→//!
  3→//! This module defines the review specialists that can examine phase outputs
  4→//! and provide quality gates before progression. Each specialist type has
  5→//! default focus areas appropriate to its domain.
  6→//!
  7→//! ## Specialist Types
  8→//!
  9→//! - [`SpecialistType::SecuritySentinel`]: Security-focused review
 10→//! - [`SpecialistType::PerformanceOracle`]: Performance-focused review
 11→//! - [`SpecialistType::ArchitectureStrategist`]: Architecture-focused review
 12→//! - [`SpecialistType::SimplicityReviewer`]: Simplicity/over-engineering review
 13→//! - [`SpecialistType::Custom`]: User-defined review type
 14→//!
 15→//! ## Example
 16→//!
 17→//! ```
 18→//! use forge::review::{ReviewSpecialist, SpecialistType};
 19→//!
 20→//! // Create a gating security review
 21→//! let security = ReviewSpecialist::new(SpecialistType::SecuritySentinel, true);
 22→//! assert_eq!(security.display_name(), "Security Sentinel");
 23→//! assert!(security.focus_areas().iter().any(|a| a.contains("injection")));
 24→//!
 25→//! // Create a non-gating custom review
 26→//! let custom = ReviewSpecialist::new(
 27→//!     SpecialistType::Custom("API Compliance".to_string()),
 28→//!     false
 29→//! ).with_focus_areas(vec!["REST conventions".to_string()]);
 30→//! ```
 31→
 32→use serde::{Deserialize, Serialize};
 33→use std::str::FromStr;
 34→
 35→/// Type of review specialist.
 36→///
 37→/// Each type represents a domain of expertise with default focus areas.
 38→///
 39→/// ## Deserialization
 40→///
 41→/// This type supports multiple deserialization formats:
 42→/// - Short-form strings: `"security"`, `"performance"`, `"architecture"`, `"simplicity"`
 43→/// - Long-form strings: `"security_sentinel"`, `"performance_oracle"`, etc.
 44→/// - Hyphenated strings: `"security-sentinel"`, `"performance-oracle"`, etc.
 45→/// - Tagged object for custom: `{"custom": "my-review"}`
 46→#[derive(Debug, Clone, Default, Serialize, PartialEq, Eq, Hash)]
 47→#[serde(rename_all = "snake_case")]
 48→pub enum SpecialistType {
 49→    /// Security-focused review examining vulnerabilities and security best practices.
 50→    #[default]
 51→    SecuritySentinel,
 52→    /// Performance-focused review examining efficiency and resource usage.
 53→    PerformanceOracle,
 54→    /// Architecture-focused review examining design patterns and structure.
 55→    ArchitectureStrategist,
 56→    /// Simplicity-focused review examining over-engineering and complexity.
 57→    SimplicityReviewer,
 58→    /// Custom review type with user-defined name.
 59→    Custom(String),
 60→}
 61→
 62→impl SpecialistType {
 63→    /// Get the human-readable display name for this specialist type.
 64→    ///
 65→    /// # Examples
 66→    ///
 67→    /// ```
 68→    /// use forge::review::SpecialistType;
 69→    ///
 70→    /// assert_eq!(SpecialistType::SecuritySentinel.display_name(), "Security Sentinel");
 71→    /// assert_eq!(SpecialistType::Custom("My Review".to_string()).display_name(), "My Review");
 72→    /// ```
 73→    pub fn display_name(&self) -> &str {
 74→        match self {
 75→            Self::SecuritySentinel => "Security Sentinel",
 76→            Self::PerformanceOracle => "Performance Oracle",
 77→            Self::ArchitectureStrategist => "Architecture Strategist",
 78→            Self::SimplicityReviewer => "Simplicity Reviewer",
 79→            Self::Custom(name) => name,
 80→        }
 81→    }
 82→
 83→    /// Get the agent name used for spawning review agents.
 84→    ///
 85→    /// This is a lowercase, hyphenated version suitable for agent identifiers.
 86→    ///
 87→    /// # Examples
 88→    ///
 89→    /// ```
 90→    /// use forge::review::SpecialistType;
 91→    ///
 92→    /// assert_eq!(SpecialistType::SecuritySentinel.agent_name(), "security-sentinel");
 93→    /// assert_eq!(SpecialistType::Custom("Code Quality".to_string()).agent_name(), "code-quality");
 94→    /// ```
 95→    pub fn agent_name(&self) -> String {
 96→        match self {
 97→            Self::SecuritySentinel => "security-sentinel".to_string(),
 98→            Self::PerformanceOracle => "performance-oracle".to_string(),
 99→            Self::ArchitectureStrategist => "architecture-strategist".to_string(),
100→            Self::SimplicityReviewer => "simplicity-reviewer".to_string(),
101→            Self::Custom(name) => name.to_lowercase().replace(' ', "-"),
102→        }
103→    }
104→
105→    /// Get a short description of what this specialist does.
106→    pub fn description(&self) -> &str {
107→        match self {
108→            Self::SecuritySentinel => {
109→                "Examines code for security vulnerabilities, authentication weaknesses, and data exposure risks. Acts as a gating reviewer — issues must be resolved before a phase can complete."
110→            }
111→            Self::PerformanceOracle => {
112→                "Analyzes code for performance bottlenecks, resource inefficiencies, and scalability concerns. Operates in advisory mode — findings are reported but don't block progress."
113→            }
114→            Self::ArchitectureStrategist => {
115→                "Reviews structural design decisions, module boundaries, and dependency relationships. Acts as a gating reviewer — architectural issues must be addressed before proceeding."
116→            }
117→            Self::SimplicityReviewer => {
118→                "Identifies over-engineering, unnecessary complexity, and YAGNI violations. Operates in advisory mode — encourages simplicity without blocking delivery."
119→            }
120→            Self::Custom(name) => {
121→                // Return static str not possible for dynamic, but we use a fallback
122→                let _ = name;
123→                "Custom review specialist with user-defined focus areas."
124→            }
125→        }
126→    }
127→
128→    /// Whether this specialist type gates phase completion by default.
129→    pub fn default_gating(&self) -> bool {
130→        match self {
131→            Self::SecuritySentinel | Self::ArchitectureStrategist => true,
132→            Self::PerformanceOracle | Self::SimplicityReviewer => false,
133→            Self::Custom(_) => false,
134→        }
135→    }
136→
137→    /// Get the default focus areas for this specialist type.
138→    ///
139→    /// Returns a list of specific concerns this specialist should examine.
140→    /// Custom specialists return an empty list by default.
141→    ///
142→    /// # Examples
143→    ///
144→    /// ```
145→    /// use forge::review::SpecialistType;
146→    ///
147→    /// let security = SpecialistType::SecuritySentinel;
148→    /// let areas = security.focus_areas();
149→    /// assert!(areas.iter().any(|a| a.contains("injection")));
150→    /// ```
151→    pub fn focus_areas(&self) -> Vec<&'static str> {
152→        match self {
153→            Self::SecuritySentinel => vec![
154→                "SQL injection vulnerabilities",
155→                "Cross-site scripting (XSS)",
156→                "Authentication bypass risks",
157→                "Secrets exposure in code or logs",
158→                "Input validation gaps",
159→                "Command injection vectors",
160→                "Path traversal vulnerabilities",
161→                "Insecure deserialization",
162→            ],
163→            Self::PerformanceOracle => vec![
164→                "N+1 query patterns",
165→                "Missing database indexes",
166→                "Memory leaks and unbounded growth",
167→                "Algorithmic complexity issues",
168→                "Unnecessary allocations",
169→                "Blocking operations in async code",
170→                "Cache misuse or missing caching",
171→                "Inefficient data structures",
172→            ],
173→            Self::ArchitectureStrategist => vec![
174→                "SOLID principle violations",
175→                "Excessive coupling between modules",
176→                "Layering violations",
177→                "Separation of concerns issues",
178→                "Circular dependencies",
179→                "Inconsistent abstraction levels",
180→                "Missing or weak interfaces",
181→                "God objects or functions",
182→            ],
183→            Self::SimplicityReviewer => vec![
184→                "Over-engineering patterns",
185→                "Premature abstraction",
186→                "YAGNI violations",
187→                "Unnecessary complexity",
188→                "Dead code or unused features",
189→                "Overly clever solutions",
190→                "Excessive indirection",
191→                "Configuration over convention abuse",
192→            ],
193→            Self::Custom(_) => vec![],
194→        }
195→    }
196→
197→    /// Check if this is a built-in specialist type.
198→    ///
199→    /// # Examples
200→    ///
201→    /// ```
202→    /// use forge::review::SpecialistType;
203→    ///
204→    /// assert!(SpecialistType::SecuritySentinel.is_builtin());
205→    /// assert!(!SpecialistType::Custom("Test".to_string()).is_builtin());
206→    /// ```
207→    pub fn is_builtin(&self) -> bool {
208→        !matches!(self, Self::Custom(_))
209→    }
210→
211→    /// Get all built-in specialist types.
212→    ///
213→    /// # Examples
214→    ///
215→    /// ```
216→    /// use forge::review::SpecialistType;
217→    ///
218→    /// let builtins = SpecialistType::all_builtins();
219→    /// assert_eq!(builtins.len(), 4);
220→    /// ```
221→    pub fn all_builtins() -> Vec<Self> {
222→        vec![
223→            Self::SecuritySentinel,
224→            Self::PerformanceOracle,
225→            Self::ArchitectureStrategist,
226→            Self::SimplicityReviewer,
227→        ]
228→    }
229→}
230→
231→impl std::fmt::Display for SpecialistType {
232→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
233→        write!(f, "{}", self.display_name())
234→    }
235→}
236→
237→/// Custom `Deserialize` for `SpecialistType`.
238→///
239→/// Supports three formats:
240→/// 1. Short-form string alias: `"security"`, `"perf"`, `"architecture"`, `"simplicity"`, etc.
241→/// 2. Long-form snake_case string: `"security_sentinel"`, `"performance_oracle"`, etc.
242→/// 3. Tagged object for custom variants: `{"custom": "my-review"}`
243→///
244→/// All string forms are routed through `FromStr`, which handles all known aliases and falls
245→/// back to `Custom(...)` for unrecognized values. The tagged object form is handled by an
246→/// internal visitor that mirrors the `#[serde(rename_all = "snake_case")]` enum layout.
247→impl<'de> serde::Deserialize<'de> for SpecialistType {
248→    fn deserialize<D: serde::Deserializer<'de>>(deserializer: D) -> Result<Self, D::Error> {
249→        use serde::de::{self, Visitor};
250→
251→        struct SpecialistTypeVisitor;
252→
253→        impl<'de> Visitor<'de> for SpecialistTypeVisitor {
254→            type Value = SpecialistType;
255→
256→            fn expecting(&self, formatter: &mut std::fmt::Formatter) -> std::fmt::Result {
257→                formatter.write_str(
258→                    r#"a specialist type string (e.g. "security", "security_sentinel") or a tagged object (e.g. {"custom": "my-review"})"#,
259→                )
260→            }
261→
262→            /// Handle plain string values via `FromStr` — supports all aliases.
263→            fn visit_str<E: de::Error>(self, value: &str) -> Result<SpecialistType, E> {
264→                SpecialistType::from_str(value).map_err(de::Error::custom)
265→            }
266→
267→            /// Handle map values — only `{"custom": "<name>"}` is valid.
268→            fn visit_map<A: de::MapAccess<'de>>(
269→                self,
270→                mut map: A,
271→            ) -> Result<SpecialistType, A::Error> {
272→                let key: String = map
273→                    .next_key()?
274→                    .ok_or_else(|| de::Error::custom("expected a key in specialist type object"))?;
275→
276→                if key == "custom" {
277→                    let value: String = map.next_value()?;
278→                    // Drain any remaining keys (there should be none).
279→                    while map.next_key::<serde::de::IgnoredAny>()?.is_some() {
280→                        map.next_value::<serde::de::IgnoredAny>()?;
281→                    }
282→                    Ok(SpecialistType::Custom(value))
283→                } else {
284→                    Err(de::Error::unknown_variant(
285→                        &key,
286→                        &[
287→                            "security_sentinel",
288→                            "performance_oracle",
289→                            "architecture_strategist",
290→                            "simplicity_reviewer",
291→                            "custom",
292→                        ],
293→                    ))
294→                }
295→            }
296→        }
297→
298→        deserializer.deserialize_any(SpecialistTypeVisitor)
299→    }
300→}
301→
302→impl FromStr for SpecialistType {
303→    type Err = std::convert::Infallible;
304→
305→    /// Parse a specialist type from a string identifier.
306→    ///
307→    /// Recognizes common aliases and falls back to Custom for unknown values.
308→    /// This implementation never fails - unknown strings become Custom variants.
309→    ///
310→    /// # Examples
311→    ///
312→    /// ```
313→    /// use forge::review::SpecialistType;
314→    /// use std::str::FromStr;
315→    ///
316→    /// assert_eq!(SpecialistType::from_str("security").unwrap(), SpecialistType::SecuritySentinel);
317→    /// assert_eq!(SpecialistType::from_str("perf").unwrap(), SpecialistType::PerformanceOracle);
318→    /// assert_eq!(SpecialistType::from_str("unknown").unwrap(), SpecialistType::Custom("unknown".to_string()));
319→    /// ```
320→    fn from_str(s: &str) -> Result<Self, Self::Err> {
321→        Ok(match s.to_lowercase().as_str() {
322→            "security" | "security-sentinel" | "security_sentinel" => Self::SecuritySentinel,
323→            "performance" | "perf" | "performance-oracle" | "performance_oracle" => {
324→                Self::PerformanceOracle
325→            }
326→            "architecture" | "arch" | "architecture-strategist" | "architecture_strategist" => {
327→                Self::ArchitectureStrategist
328→            }
329→            "simplicity" | "simple" | "simplicity-reviewer" | "simplicity_reviewer" => {
330→                Self::SimplicityReviewer
331→            }
332→            _ => Self::Custom(s.to_string()),
333→        })
334→    }
335→}
