337→/// Configuration for a review specialist.
338→///
339→/// Combines a specialist type with gating behavior and optional custom focus areas.
340→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
341→pub struct ReviewSpecialist {
342→    /// Type of specialist.
343→    pub specialist_type: SpecialistType,
344→    /// Whether this review gates phase completion.
345→    /// If true, failures must be resolved before proceeding.
346→    #[serde(default)]
347→    pub gate: bool,
348→    /// Custom focus areas (overrides defaults if non-empty).
349→    #[serde(default)]
350→    pub custom_focus_areas: Vec<String>,
351→}
352→
353→impl ReviewSpecialist {
354→    /// Create a new review specialist configuration.
355→    ///
356→    /// # Arguments
357→    ///
358→    /// * `specialist_type` - The type of specialist
359→    /// * `gate` - Whether failures should block phase completion
360→    ///
361→    /// # Examples
362→    ///
363→    /// ```
364→    /// use forge::review::{ReviewSpecialist, SpecialistType};
365→    ///
366→    /// let gating = ReviewSpecialist::new(SpecialistType::SecuritySentinel, true);
367→    /// assert!(gating.gate);
368→    ///
369→    /// let advisory = ReviewSpecialist::new(SpecialistType::PerformanceOracle, false);
370→    /// assert!(!advisory.gate);
371→    /// ```
372→    pub fn new(specialist_type: SpecialistType, gate: bool) -> Self {
373→        Self {
374→            specialist_type,
375→            gate,
376→            custom_focus_areas: Vec::new(),
377→        }
378→    }
379→
380→    /// Create a gating review specialist.
381→    ///
382→    /// Convenience method for creating specialists that block on failures.
383→    pub fn gating(specialist_type: SpecialistType) -> Self {
384→        Self::new(specialist_type, true)
385→    }
386→
387→    /// Create a non-gating (advisory) review specialist.
388→    ///
389→    /// Convenience method for creating specialists that only warn.
390→    pub fn advisory(specialist_type: SpecialistType) -> Self {
391→        Self::new(specialist_type, false)
392→    }
393→
394→    /// Add custom focus areas to this specialist.
395→    ///
396→    /// Custom focus areas replace the default ones when non-empty.
397→    ///
398→    /// # Examples
399→    ///
400→    /// ```
401→    /// use forge::review::{ReviewSpecialist, SpecialistType};
402→    ///
403→    /// let specialist = ReviewSpecialist::new(SpecialistType::SecuritySentinel, true)
404→    ///     .with_focus_areas(vec!["API key exposure".to_string()]);
405→    ///
406→    /// let areas = specialist.focus_areas();
407→    /// assert_eq!(areas.len(), 1);
408→    /// assert_eq!(areas[0], "API key exposure");
409→    /// ```
410→    pub fn with_focus_areas(mut self, areas: Vec<String>) -> Self {
411→        self.custom_focus_areas = areas;
412→        self
413→    }
414→
415→    /// Get the display name for this specialist.
416→    pub fn display_name(&self) -> &str {
417→        self.specialist_type.display_name()
418→    }
419→
420→    /// Get the agent name for this specialist.
421→    pub fn agent_name(&self) -> String {
422→        self.specialist_type.agent_name()
423→    }
424→
425→    /// Get the focus areas for this specialist.
426→    ///
427→    /// Returns custom focus areas if set, otherwise returns default focus areas
428→    /// for the specialist type.
429→    ///
430→    /// # Examples
431→    ///
432→    /// ```
433→    /// use forge::review::{ReviewSpecialist, SpecialistType};
434→    ///
435→    /// // Default focus areas
436→    /// let specialist = ReviewSpecialist::new(SpecialistType::SecuritySentinel, true);
437→    /// let areas = specialist.focus_areas();
438→    /// assert!(areas.iter().any(|a| a.contains("injection")));
439→    ///
440→    /// // Custom focus areas override defaults
441→    /// let custom = specialist.with_focus_areas(vec!["Custom area".to_string()]);
442→    /// assert_eq!(custom.focus_areas(), vec!["Custom area"]);
443→    /// ```
444→    pub fn focus_areas(&self) -> Vec<&str> {
445→        if self.custom_focus_areas.is_empty() {
446→            self.specialist_type.focus_areas()
447→        } else {
448→            self.custom_focus_areas.iter().map(|s| s.as_str()).collect()
449→        }
450→    }
451→
452→    /// Check if this specialist gates phase completion.
453→    pub fn is_gating(&self) -> bool {
454→        self.gate
455→    }
456→
457→    /// Check if this is a built-in specialist type.
458→    pub fn is_builtin(&self) -> bool {
459→        self.specialist_type.is_builtin()
460→    }
461→
462→    /// Create all built-in specialists configured as gating.
463→    ///
464→    /// Used by sensitive phase detection to enable full review coverage.
465→    pub fn all_builtin_as_gating() -> Vec<Self> {
466→        SpecialistType::all_builtins()
467→            .into_iter()
468→            .map(Self::gating)
469→            .collect()
470→    }
471→}
472→
473→impl Default for ReviewSpecialist {
474→    fn default() -> Self {
475→        Self::gating(SpecialistType::SecuritySentinel)
476→    }
477→}
478→
479→impl std::fmt::Display for ReviewSpecialist {
480→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
481→        if self.gate {
482→            write!(f, "{} (gating)", self.specialist_type)
483→        } else {
484→            write!(f, "{} (advisory)", self.specialist_type)
485→        }
486→    }
487→}
