 309→    pub fn with_defaults() -> Self {
 310→        Self::new(DispatcherConfig::default())
 311→    }
 312→
 313→    /// Dispatch review specialists for a phase.
 314→    ///
 315→    /// This is the main entry point for review dispatch. It:
 316→    /// 1. Runs all configured review specialists
 317→    /// 2. Aggregates their findings
 318→    /// 3. Invokes the arbiter if there are gating failures
 319→    /// 4. Returns the dispatch result
 320→    pub async fn dispatch(&self, review_config: PhaseReviewConfig) -> Result<DispatchResult> {
 321→        let start = Instant::now();
 322→        info!(
 323→            specialists = review_config.specialists.len(),
 324→            phase = %review_config.phase,
 325→            "Review dispatch started"
 326→        );
 327→
 328→        if review_config.specialists.is_empty() {
 329→            // No specialists configured, return empty success
 330→            return Ok(DispatchResult::success(
 331→                ReviewAggregation::new(&review_config.phase),
 332→                start.elapsed(),
 333→            ));
 334→        }
 335→
 336→        if self.config.verbose {
 337→            debug!(
 338→                "Dispatching {} specialists for phase {}",
 339→                review_config.specialists.len(),
 340→                review_config.phase
 341→            );
 342→        }
 343→
 344→        // Run review specialists
 345→        let reports = if self.config.parallel {
 346→            self.run_parallel_reviews(&review_config).await?
 347→        } else {
 348→            self.run_sequential_reviews(&review_config).await?
 349→        };
 350→
 351→        // Build aggregation
 352→        let aggregation = ReviewAggregation::new(&review_config.phase)
 353→            .add_reports(reports)
 354→            .with_parallel_execution(self.config.parallel)
 355→            .with_total_duration_ms(start.elapsed().as_millis() as u64);
 356→
 357→        info!(
 358→            total_findings = aggregation.all_findings_count(),
 359→            reports = aggregation.reports_count(),
 360→            verdict = %aggregation.overall_verdict(),
 361→            "Review aggregation complete"
 362→        );
 363→
 364→        if self.config.verbose {
 365→            debug!(
 366→                "Aggregation complete: {} reports, {} findings, verdict: {}",
 367→                aggregation.reports_count(),
 368→                aggregation.all_findings_count(),
 369→                aggregation.overall_verdict()
 370→            );
 371→        }
 372→
 373→        // Handle gating failures via arbiter
 374→        if aggregation.has_gating_failures() && review_config.has_gating_specialists() {
 375→            let arbiter_result = self.invoke_arbiter(&aggregation, &review_config).await?;
 376→            Ok(DispatchResult::with_arbiter(
 377→                aggregation,
 378→                arbiter_result,
 379→                start.elapsed(),
 380→            ))
 381→        } else {
 382→            Ok(DispatchResult::success(aggregation, start.elapsed()))
 383→        }
 384→    }
 385→
 386→    /// Run review specialists in parallel.
 387→    async fn run_parallel_reviews(
 388→        &self,
 389→        review_config: &PhaseReviewConfig,
 390→    ) -> Result<Vec<ReviewReport>> {
 391→        use futures::future::join_all;
 392→
 393→        let futures: Vec<_> = review_config
 394→            .specialists
 395→            .iter()
 396→            .map(|specialist| self.run_single_review(specialist, review_config))
 397→            .collect();
 398→
 399→        let results = join_all(futures).await;
 400→
 401→        let mut reports = Vec::new();
 402→        for result in results {
 403→            match result {
 404→                Ok(report) => reports.push(report),
 405→                Err(e) => {
 406→                    warn!("Specialist failed: {}", e);
 407→                    // Continue with other reviews
 408→                }
 409→            }
 410→        }
 411→
 412→        Ok(reports)
 413→    }
 414→
 415→    /// Run review specialists sequentially.
 416→    async fn run_sequential_reviews(
 417→        &self,
 418→        review_config: &PhaseReviewConfig,
 419→    ) -> Result<Vec<ReviewReport>> {
 420→        let mut reports = Vec::new();
 421→
 422→        for specialist in &review_config.specialists {
 423→            match self.run_single_review(specialist, review_config).await {
 424→                Ok(report) => reports.push(report),
 425→                Err(e) => {
 426→                    warn!("Specialist {} failed: {}", specialist.display_name(), e);
 427→                    // Continue with other reviews
 428→                }
 429→            }
 430→        }
 431→
 432→        Ok(reports)
 433→    }
 434→
 435→    /// Run a single review specialist.
 436→    async fn run_single_review(
 437→        &self,
 438→        specialist: &ReviewSpecialist,
 439→        review_config: &PhaseReviewConfig,
 440→    ) -> Result<ReviewReport> {
 441→        let start = Instant::now();
 442→
 443→        if self.config.verbose {
 444→            debug!(
 445→                "Starting {} for phase {}",
 446→                specialist.display_name(),
 447→                review_config.phase
 448→            );
 449→        }
 450→
 451→        // Build the review prompt
 452→        let prompt = build_review_prompt(specialist, review_config);
 453→
 454→        // Run Claude with the review prompt
 455→        let output = self.run_claude_review(&prompt).await?;
 456→
 457→        // Parse the review output
 458→        let report = parse_review_output(
 459→            &output,
 460→            &review_config.phase,
 461→            &specialist.agent_name(),
 462→            specialist.is_gating(),
 463→        )
 464→        .with_duration_ms(start.elapsed().as_millis() as u64);
 465→
 466→        if self.config.verbose {
 467→            debug!(
 468→                "{} completed: {} ({} findings)",
 469→                specialist.display_name(),
 470→                report.verdict,
 471→                report.findings_count()
 472→            );
 473→        }
 474→
 475→        Ok(report)
 476→    }
 477→
 478→    /// Run Claude to perform a review.
 479→    async fn run_claude_review(&self, prompt: &str) -> Result<String> {
 480→        let mut cmd = Command::new(&self.config.claude_cmd);
 481→        cmd.arg("--print");
 482→
 483→        if self.config.skip_permissions {
 484→            cmd.arg("--dangerously-skip-permissions");
 485→        }
 486→
 487→        // Reviews are read-only — restrict to safe tools
 488→        cmd.arg("--allowed-tools")
 489→            .arg("Read,Glob,Grep,WebSearch,WebFetch");
 490→
 491→        if let Some(ref working_dir) = self.config.working_dir {
 492→            cmd.current_dir(working_dir);
 493→        }
 494→
 495→        cmd.stdin(Stdio::piped())
 496→            .stdout(Stdio::piped())
 497→            .stderr(Stdio::inherit());
 498→
 499→        let mut child = cmd.spawn().context("Failed to spawn Claude process")?;
 500→
 501→        // Write prompt to stdin
 502→        if let Some(mut stdin) = child.stdin.take() {
 503→            stdin
 504→                .write_all(prompt.as_bytes())
 505→                .await
 506→                .context("Failed to write prompt to stdin")?;
 507→            stdin.shutdown().await.context("Failed to close stdin")?;
 508→        }
 509→
 510→        // Read stdout
 511→        let stdout = child.stdout.take().context("Failed to get stdout")?;
 512→        let reader = BufReader::new(stdout);
 513→        let mut lines = reader.lines();
 514→        let mut output = String::new();
 515→
 516→        while let Ok(Some(line)) = lines.next_line().await {
 517→            output.push_str(&line);
 518→            output.push('\n');
 519→        }
 520→
 521→        // Wait for process with timeout
 522→        let status = tokio::time::timeout(self.config.review_timeout, child.wait())
 523→            .await
 524→            .context("Review timed out")?
 525→            .context("Failed to wait for process")?;
 526→
 527→        if !status.success() {
 528→            anyhow::bail!(
 529→                "Claude review process exited with code {}",
 530→                status.code().unwrap_or(-1)
 531→            );
 532→        }
 533→
 534→        Ok(output)
 535→    }
 536→
 537→    /// Invoke the arbiter to handle gating failures.
 538→    async fn invoke_arbiter(
 539→        &self,
 540→        aggregation: &ReviewAggregation,
 541→        review_config: &PhaseReviewConfig,
 542→    ) -> Result<ArbiterResult> {
 543→        if self.config.verbose {
 544→            debug!(
 545→                "Invoking arbiter for {} gating failure(s)",
 546→                aggregation.gating_failures().len()
 547→            );
 548→        }
 549→
 550→        let executor = ArbiterExecutor::new(self.config.arbiter.clone());
 551→
 552→        let input = ArbiterInput::from_aggregation(
 553→            aggregation,
 554→            review_config.budget,
 555→            review_config.iterations_used,
 556→        )
 557→        .with_phase_name(&review_config.phase_name);
 558→
 559→        executor.decide_with_quick_check(input).await
 560→    }
 561→}
