 563→/// Build the prompt for a review specialist.
 564→fn build_review_prompt(specialist: &ReviewSpecialist, config: &PhaseReviewConfig) -> String {
 565→    let focus_areas = specialist.focus_areas();
 566→    let focus_list = focus_areas
 567→        .iter()
 568→        .map(|area| format!("- {}", area))
 569→        .collect::<Vec<_>>()
 570→        .join("\n");
 571→
 572→    let files_section = if config.files_changed.is_empty() {
 573→        "No specific files listed - review the entire phase output.".to_string()
 574→    } else {
 575→        format!(
 576→            "Focus on these changed files:\n{}",
 577→            config
 578→                .files_changed
 579→                .iter()
 580→                .map(|f| format!("- {}", f))
 581→                .collect::<Vec<_>>()
 582→                .join("\n")
 583→        )
 584→    };
 585→
 586→    let context_section = config
 587→        .additional_context
 588→        .as_ref()
 589→        .map(|ctx| format!("\n## Additional Context\n{}\n", ctx))
 590→        .unwrap_or_default();
 591→
 592→    let gating_note = if specialist.is_gating() {
 593→        "**This is a GATING review.** If you find critical issues (error severity), the phase cannot proceed until they are resolved."
 594→    } else {
 595→        "This is an advisory review. Issues will be reported but won't block phase progression."
 596→    };
 597→
 598→    format!(
 599→        r#"# {display_name} Review
 600→
 601→You are a code review specialist focused on **{display_name}** concerns.
 602→
 603→## Review Context
 604→- Phase: {phase} - {phase_name}
 605→- Reviewer Role: {display_name}
 606→{context_section}
 607→{gating_note}
 608→
 609→## Focus Areas
 610→
 611→Examine the code for these specific concerns:
 612→{focus_list}
 613→
 614→## Files to Review
 615→
 616→{files_section}
 617→
 618→## Review Instructions
 619→
 620→1. Examine the code changes carefully
 621→2. Check for issues in your focus areas
 622→3. For each issue found:
 623→   - Identify the specific file and line number
 624→   - Describe the issue clearly
 625→   - Suggest how to fix it
 626→   - Classify severity: error (critical), warning (should fix), info (nice to fix), note (observation)
 627→
 628→## Output Format
 629→
 630→Respond with a JSON object containing your review findings:
 631→
 632→```json
 633→{{
 634→  "verdict": "pass|warn|fail",
 635→  "summary": "Brief summary of your review findings",
 636→  "findings": [
 637→    {{
 638→      "severity": "error|warning|info|note",
 639→      "file": "path/to/file.rs",
 640→      "line": 42,
 641→      "issue": "Description of the issue",
 642→      "suggestion": "How to fix it"
 643→    }}
 644→  ]
 645→}}
 646→```
 647→
 648→If no issues are found, return:
 649→```json
 650→{{
 651→  "verdict": "pass",
 652→  "summary": "No {display_name} issues found",
 653→  "findings": []
 654→}}
 655→```
 656→
 657→Begin your review now.
 658→"#,
 659→        display_name = specialist.display_name(),
 660→        phase = config.phase,
 661→        phase_name = config.phase_name,
 662→        context_section = context_section,
 663→        gating_note = gating_note,
 664→        focus_list = focus_list,
 665→        files_section = files_section,
 666→    )
 667→}
