 669→/// Parse review output from Claude into a ReviewReport.
 670→fn parse_review_output(output: &str, phase: &str, reviewer: &str, is_gating: bool) -> ReviewReport {
 671→    // Try to extract JSON from the output
 672→    if let Some(json_str) = extract_json(output)
 673→        && let Ok(value) = serde_json::from_str::<serde_json::Value>(&json_str)
 674→    {
 675→        // Parse verdict
 676→        let verdict_str = value
 677→            .get("verdict")
 678→            .and_then(|v| v.as_str())
 679→            .unwrap_or("pass");
 680→        let verdict = match verdict_str.to_lowercase().as_str() {
 681→            "fail" => ReviewVerdict::Fail,
 682→            "warn" => ReviewVerdict::Warn,
 683→            _ => ReviewVerdict::Pass,
 684→        };
 685→
 686→        // Parse summary
 687→        let summary = value
 688→            .get("summary")
 689→            .and_then(|v| v.as_str())
 690→            .unwrap_or("")
 691→            .to_string();
 692→
 693→        // Parse findings
 694→        let mut findings = Vec::new();
 695→        if let Some(findings_array) = value.get("findings").and_then(|v| v.as_array()) {
 696→            for finding_value in findings_array {
 697→                if let Some(finding) = parse_finding(finding_value) {
 698→                    findings.push(finding);
 699→                }
 700→            }
 701→        }
 702→
 703→        // Determine final verdict based on findings and gating status
 704→        let final_verdict = determine_verdict(&findings, verdict, is_gating);
 705→
 706→        return ReviewReport::new(phase, reviewer, final_verdict)
 707→            .with_summary(summary)
 708→            .add_findings(findings)
 709→            .with_timestamp(chrono::Utc::now());
 710→    }
 711→
 712→    // Fallback: couldn't parse output, return warning so it's not silently ignored
 713→    warn!(
 714→        "Could not parse review output for phase '{}' by reviewer '{}' - manual inspection recommended",
 715→        phase, reviewer
 716→    );
 717→    ReviewReport::new(phase, reviewer, ReviewVerdict::Warn)
 718→        .with_summary(
 719→            "Review completed but output could not be parsed - manual inspection recommended",
 720→        )
 721→        .with_timestamp(chrono::Utc::now())
 722→}
 723→
 724→/// Parse a single finding from JSON.
 725→fn parse_finding(value: &serde_json::Value) -> Option<ReviewFinding> {
 726→    let severity_str = value.get("severity").and_then(|v| v.as_str())?;
 727→    let severity = match severity_str.to_lowercase().as_str() {
 728→        "error" => FindingSeverity::Error,
 729→        "warning" => FindingSeverity::Warning,
 730→        "info" => FindingSeverity::Info,
 731→        "note" => FindingSeverity::Note,
 732→        _ => FindingSeverity::Warning,
 733→    };
 734→
 735→    let file = value.get("file").and_then(|v| v.as_str())?;
 736→    let issue = value.get("issue").and_then(|v| v.as_str())?;
 737→
 738→    let mut finding = ReviewFinding::new(severity, file, issue);
 739→
 740→    if let Some(line) = value.get("line").and_then(|v| v.as_u64()) {
 741→        finding = finding.with_line(line as u32);
 742→    }
 743→
 744→    if let Some(column) = value.get("column").and_then(|v| v.as_u64()) {
 745→        finding = finding.with_column(column as u32);
 746→    }
 747→
 748→    if let Some(suggestion) = value.get("suggestion").and_then(|v| v.as_str()) {
 749→        finding = finding.with_suggestion(suggestion);
 750→    }
 751→
 752→    if let Some(category) = value.get("category").and_then(|v| v.as_str()) {
 753→        finding = finding.with_category(category);
 754→    }
 755→
 756→    Some(finding)
 757→}
 758→
 759→/// Determine the final verdict based on findings.
 760→fn determine_verdict(
 761→    findings: &[ReviewFinding],
 762→    stated_verdict: ReviewVerdict,
 763→    is_gating: bool,
 764→) -> ReviewVerdict {
 765→    // If there are critical (error) findings and this is gating, force fail
 766→    let has_critical = findings.iter().any(|f| f.is_critical());
 767→    let has_actionable = findings.iter().any(|f| f.is_actionable());
 768→
 769→    if is_gating && has_critical {
 770→        return ReviewVerdict::Fail;
 771→    }
 772→
 773→    if has_actionable && stated_verdict == ReviewVerdict::Pass {
 774→        // Upgrade from pass to warn if there are actionable findings
 775→        return ReviewVerdict::Warn;
 776→    }
 777→
 778→    stated_verdict
 779→}
 780→
 781→/// Extract JSON from output that may contain markdown or other text.
 782→fn extract_json(output: &str) -> Option<String> {
 783→    // Try to find JSON in a code block
 784→    if let Some(start) = output.find("```json") {
 785→        let after_marker = &output[start + 7..];
 786→        if let Some(end) = after_marker.find("```") {
 787→            return Some(after_marker[..end].trim().to_string());
 788→        }
 789→    }
 790→
 791→    // Try to find JSON in a generic code block
 792→    if let Some(start) = output.find("```") {
 793→        let after_marker = &output[start + 3..];
 794→        if let Some(end) = after_marker.find("```")
 795→            && let Some(json_start) = after_marker[..end].find('{')
 796→        {
 797→            let content = &after_marker[json_start..end];
 798→            if !content.is_empty() {
 799→                return Some(content.trim().to_string());
 800→            }
 801→        }
 802→    }
 803→
 804→    // Try to find a raw JSON object
 805→    if let Some(start) = output.find('{') {
 806→        let mut depth = 0;
 807→        let mut end = start;
 808→        for (i, c) in output[start..].char_indices() {
 809→            match c {
 810→                '{' => depth += 1,
 811→                '}' => {
 812→                    depth -= 1;
 813→                    if depth == 0 {
 814→                        end = start + i + 1;
 815→                        break;
 816→                    }
 817→                }
 818→                _ => {}
 819→            }
 820→        }
 821→        if depth == 0 && end > start {
 822→            return Some(output[start..end].to_string());
 823→        }
 824→    }
 825→
 826→    None
 827→}
