            PromptMode::Gating
        } else {
            PromptMode::Advisory
        };

        assert_eq!(
            config.specialist_name,
            specialist.display_name(),
            "specialist_name mismatch for {}",
            specialist.agent_name()
        );
        assert_eq!(
            config.mode, expected_mode,
            "mode mismatch for {}",
            specialist.agent_name()
        );
        assert_eq!(
            config.focus_areas, expected_focus,
            "focus_areas mismatch for {}",
            specialist.agent_name()
        );
    }

